dashboardQueries.query:
ioc.feed_log_type = "GCP_THREATINTEL"
ioc.feed_name = "Google Threat Intelligence"


$ioc_val = ioc.ioc_value 
// $ioc_type = ioc.ioc_type
$confidence_score_val = ioc.confidence_score 
$match_bucket = timestamp.get_timestamp(ioc.day_bucket_seconds) 
$category = ioc.category
$latitude = ioc.location.region_coordinates.latitude
$longitude = ioc.location.region_coordinates.longitude
$country = if(ioc.location.country_or_region != "", ioc.location.country_or_region, "-") 
$ioc_type = (if(ioc.ioc_type = "IOC_TYPE_IP", "ip-address",
            if(ioc.ioc_type = "IOC_TYPE_DOMAIN", "domain",
                if(ioc.ioc_type = "IOC_TYPE_FILE", "file",
                    if(ioc.ioc_type = "IOC_TYPE_FILE_HASH_MD5", "file-hash-md5",
                        if(ioc.ioc_type = "IOC_TYPE_FILE_HASH_SHA256", "file-hash-sha256",
                            if(ioc.ioc_type = "IOC_TYPE_FILE_HASH_SHA1", "file-hash-sha1", "unknown")
                        )
                    )
                )
            )
        )
    )
match: 
    $ioc_val, $ioc_type
outcome: 
    $count = count_distinct(strings.concat($ioc_val, "|", $ioc_type, "|", cast.as_string(cast.as_int($latitude * 1000000)), "|", cast.as_string(cast.as_int($longitude * 1000000)), "|", $country, "|", $match_bucket))
    $confidence_score = array_distinct($confidence_score_val)
    $asset_hostname = re.replace((arrays.join_string(array_distinct(if(ioc.asset.hostname!="", ioc.asset.hostname, "-")),", ")), "(, -)|(-, )","")
    $asset_ip_address = re.replace((arrays.join_string(array_distinct(if(ioc.asset.asset_ip_address!="", ioc.asset.asset_ip_address, "-")),", ")), "(, -)|(-, )","")
    
order: 
    $count desc
limit: 
    10

