ioc.feed_log_type = "GCP_THREATINTEL"
ioc.feed_name = "Google Threat Intelligence"
$ioc_val = ioc.ioc_value
$ioc_type = ioc.ioc_type
$confidence = ioc.confidence_score
$match_bucket = timestamp.get_date(ioc.day_bucket_seconds)
$latitude = ioc.location.region_coordinates.latitude
$longitude = ioc.location.region_coordinates.latitude
$country = if(ioc.location.country_or_region!="", ioc.location.country_or_region, "-") 
match: 
    $ioc_val, $ioc_type, $latitude, $longitude, $match_bucket, $country, $confidence
outcome:
    $gti_ioc_link = array_distinct(
        strings.concat("https://virustotal.com/gui/", (if(ioc.ioc_type = "IOC_TYPE_IP", "ip-address",
            if(ioc.ioc_type = "IOC_TYPE_DOMAIN", "domain",
                if(ioc.ioc_type = "IOC_TYPE_FILE", "file",
                    if(ioc.ioc_type = "IOC_TYPE_FILE_HASH_MD5", "file-hash-md5",
                        if(ioc.ioc_type = "IOC_TYPE_FILE_HASH_SHA256", "file-hash-sha256",
                            if(ioc.ioc_type = "IOC_TYPE_FILE_HASH_SHA1", "file-hash-sha1", "unknown")
                        )
                    )
                )
            )
        )),"/",$ioc_val)
    )
    $classification = array_distinct(strings.to_upper(ioc.severity))
    $category = array_distinct(ioc.category)
    $hostname = re.replace(re.replace(re.replace(arrays.join_string(array_distinct(ioc.asset.hostname), ","), ",,+", ","), "^,|,$", ""), "^\\s*$|^$", "-")
order:
    $match_bucket desc
limit:
    10000
